doc = Document("docs/07-Release-Documents/RDS_Document.docx")

# ---- 0. Xoa cac doan huong dan (instructional text) khong can trong output ----
def del_by_text(doc, substr, occurrence=0):
    children = list(doc.element.body.iterchildren())
    i = find_paragraph_index(doc, substr, occurrence)
    children[i].getparent().remove(children[i])

def del_range_before(doc, start_substr, end_substr):
    """Xoa moi phan tu tu start_substr (inclusive) den truoc end_substr (exclusive)."""
    children = list(doc.element.body.iterchildren())
    i1 = find_paragraph_index(doc, start_substr)
    i2 = find_paragraph_index(doc, end_substr)
    for c in children[i1:i2]:
        c.getparent().remove(c)

# xoa khoi "Functional Description Contents" (huong dan dai)
del_range_before(doc, "Functional Description Contents", "b. Business Rules")
# xoa cau huong dan truoc bang Functional Description
del_by_text(doc, "Provide the functional description for the use cases")
# xoa cau huong dan truoc bang Business Rules
del_by_text(doc, "Provide the business rules those are applied only to the use case")

