assert len(UCS) == N, f"expected {N} UC, got {len(UCS)}"

for i, (rng, uc) in enumerate(zip(ranges, UCS), start=1):
    tabs = tables_in_range(doc, rng)
    fd, br = tabs[0], tabs[1]
    # heading 1.N
    head_el = rng[0]
    hp = Paragraph(head_el, doc)
    set_paragraph_text(hp, f"1.{i} {uc['code']}_{uc['name']}")
    # Functional Description table (15 rows x 4 cols)
    set_cell_text(fd.rows[0].cells[1], f"{uc['code']}_{uc['name']}")
    set_cell_text(fd.rows[1].cells[1], uc['created_by']); set_cell_text(fd.rows[1].cells[3], uc['date'])
    set_cell_text(fd.rows[2].cells[1], uc['actor']); set_cell_text(fd.rows[2].cells[3], uc['sec_actor'])
    set_cell_text(fd.rows[3].cells[1], uc['trigger'])
    set_cell_text(fd.rows[4].cells[1], uc['desc'])
    set_cell_text(fd.rows[5].cells[1], uc['pre'])
    set_cell_text(fd.rows[6].cells[1], uc['post'])
    set_cell_text(fd.rows[7].cells[1], uc['normal'])
    set_cell_text(fd.rows[8].cells[1], uc['alt'])
    set_cell_text(fd.rows[9].cells[1], uc['exc'])
    set_cell_text(fd.rows[10].cells[1], uc['priority'])
    set_cell_text(fd.rows[11].cells[1], uc['freq'])
    set_cell_text(fd.rows[12].cells[1], ", ".join(b[0] for b in uc['biz'] if b[0] != "—"))
    other = uc['other'] + ("\n" + uc.get('note','') if uc.get('note') else "")
    set_cell_text(fd.rows[13].cells[1], other)
    set_cell_text(fd.rows[14].cells[1], uc['assumptions'])
    # Business Rules table
    r0 = uc['biz'][0]
    set_cell_text(br.rows[1].cells[0], r0[0]); set_cell_text(br.rows[1].cells[1], r0[1]); set_cell_text(br.rows[1].cells[2], r0[2])
    for r in uc['biz'][1:]:
        last_tr = br.rows[-1]._tr
        new_tr = copy.deepcopy(last_tr)
        last_tr.addnext(new_tr)
        new_row = br.rows[-1]
        for ci, val in enumerate(r):
            set_cell_text(new_row.cells[ci], val)

